import React, { useState, useEffect } from 'react';
import { UserData, SystemConfig } from '../App';
import { useLanguage } from './LanguageContext';

interface LoginScreenProps {
  onLoginSuccess: (username: string, role: 'ADMIN' | 'USER' | 'LEADER') => void;
  users: UserData[];
  systemConfig: SystemConfig;
}

const LoginScreen: React.FC<LoginScreenProps> = ({ onLoginSuccess, users, systemConfig }) => {
  const [username, setUsername] = useState<string>('');
  const [password, setPassword] = useState<string>('');
  const [error, setError] = useState<string>('');
  const { t } = useLanguage();

  // IP Check State
  const [clientIP, setClientIP] = useState<string | null>(null);
  const [isIpAllowed, setIsIpAllowed] = useState<boolean>(true);
  const [loadingIp, setLoadingIp] = useState<boolean>(false);

  // Scheduled Maintenance Check
  const now = new Date();
  const currentISO = new Date(now.getTime() - (now.getTimezoneOffset() * 60000)).toISOString().slice(0, 16);
  const isScheduledMaintenance = systemConfig.maintenanceStart && systemConfig.maintenanceEnd && 
                                 currentISO >= systemConfig.maintenanceStart && 
                                 currentISO <= systemConfig.maintenanceEnd;
  const isMaintenance = systemConfig.maintenanceMode || isScheduledMaintenance;

  useEffect(() => {
      // Fetch Client IP if check is enabled
      if (systemConfig.ipCheckEnabled) {
          setLoadingIp(true);
          fetch('https://api.ipify.org?format=json')
              .then(res => res.json())
              .then(data => {
                  setClientIP(data.ip);
                  checkIpAgainstWhitelist(data.ip);
              })
              .catch(err => {
                  console.error('IP fetch failed', err);
                  setClientIP('Unknown');
                  setIsIpAllowed(true); 
              })
              .finally(() => setLoadingIp(false));
      } else {
          setIsIpAllowed(true);
      }
  }, [systemConfig.ipCheckEnabled, systemConfig.allowedIPs]);

  const checkIpAgainstWhitelist = (ip: string) => {
      if (!systemConfig.allowedIPs || systemConfig.allowedIPs.length === 0) {
          setIsIpAllowed(true); // Empty list = allow all
          return;
      }

      const allowed = systemConfig.allowedIPs.some(pattern => {
          if (pattern.includes('*')) {
              const prefix = pattern.split('*')[0];
              return ip.startsWith(prefix);
          }
          return pattern === ip;
      });
      setIsIpAllowed(allowed);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const normalizedInputUsername = username.trim().toUpperCase();

    // Check IP First
    if (systemConfig.ipCheckEnabled && !isIpAllowed) {
        const foundUser = users.find(u => u.username.toUpperCase() === normalizedInputUsername);

        if (foundUser && foundUser.password === password) {
             if (foundUser.role === 'ADMIN') {
                 onLoginSuccess(foundUser.username, foundUser.role);
                 return;
             }
        }
        setError(t('ip_blocked_title')); 
        return;
    }

    const foundUser = users.find(u => u.username.toUpperCase() === normalizedInputUsername);

    if (foundUser && foundUser.password === password) {
      if (isMaintenance && foundUser.role !== 'ADMIN') {
          setError(t('login_error_maint'));
      } else {
          setError('');
          onLoginSuccess(foundUser.username, foundUser.role);
      }
    } else {
      setError(t('login_error'));
    }
  };

  return (
    <div className="flex flex-col items-center w-full max-w-md mx-4">

      {/* Maintenance Banner */}
      {isMaintenance && (
          <div className="w-full mb-6 bg-yellow-900/50 border border-yellow-600 p-4 rounded-xl text-center animate-pulse">
              <h3 className="text-xl font-bold text-yellow-500 uppercase">{t('maint_active_title')}</h3>
              <p className="text-yellow-200 text-sm mt-1">{t('maint_active_desc')}</p>
              {isScheduledMaintenance && (
                  <p className="text-xs text-yellow-400 mt-2 font-mono">
                      {t('maint_scheduled_msg', { 
                          start: new Date(systemConfig.maintenanceStart!).toLocaleString(), 
                          end: new Date(systemConfig.maintenanceEnd!).toLocaleString() 
                      })}
                  </p>
              )}
          </div>
      )}

      {/* IP Block Banner */}
      {systemConfig.ipCheckEnabled && !loadingIp && !isIpAllowed && (
           <div className="w-full mb-6 bg-red-900/50 border border-red-600 p-4 rounded-xl text-center">
               <h3 className="text-xl font-bold text-red-500 uppercase">{t('ip_blocked_title')}</h3>
               <p className="text-red-200 text-sm mt-1">{t('ip_blocked_desc', { ip: clientIP || 'Unknown' })}</p>
           </div>
      )}

      <div className="w-full p-6 sm:p-8 space-y-6 sm:space-y-8 bg-gray-800 rounded-xl shadow-lg relative overflow-hidden">
        {loadingIp && (
            <div className="absolute inset-0 bg-gray-900/80 flex items-center justify-center z-50">
                <p className="text-teal-400 animate-pulse font-bold">{t('checking_ip')}</p>
            </div>
        )}

        <div className="text-center">
          <h2 className="text-3xl font-extrabold text-[#97bc1e] mb-2">
            {t('login_title')}
          </h2>
          <p className="mt-2 text-sm text-gray-400">
            {t('login_subtitle')}
          </p>
        </div>
        <form className="mt-6 sm:mt-8 space-y-6" onSubmit={handleSubmit}>
          <div className="rounded-md shadow-sm -space-y-px">
            <div>
              <label htmlFor="username" className="sr-only">{t('username')}</label>
              <input
                id="username"
                name="username"
                type="text"
                autoComplete="username"
                required
                autoFocus
                className={`appearance-none rounded-none rounded-t-md relative block w-full px-3 py-3 border placeholder-gray-500 text-white bg-gray-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-gray-800 focus:ring-teal-500 focus:z-10 text-base sm:text-sm ${error ? 'border-red-500' : 'border-gray-600'}`}
                placeholder={t('username')}
                value={username}
                onChange={(e) => {
                  setUsername(e.target.value);
                  if (error) setError('');
                }}
              />
            </div>
            <div>
              <label htmlFor="password" className="sr-only">{t('password')}</label>
              <input
                id="password"
                name="password"
                type="password"
                autoComplete="current-password"
                required
                className={`appearance-none rounded-none rounded-b-md relative block w-full px-3 py-3 border placeholder-gray-500 text-white bg-gray-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-gray-800 focus:ring-teal-500 focus:z-10 text-base sm:text-sm ${error ? 'border-red-500' : 'border-gray-600'}`}
                placeholder={t('password')}
                value={password}
                onChange={(e) => {
                  setPassword(e.target.value);
                  if (error) setError('');
                }}
              />
            </div>
          </div>

          {error && <p className="text-sm text-red-400 text-center font-bold">{error}</p>}

          <div>
            <button
              type="submit"
              disabled={systemConfig.ipCheckEnabled && !isIpAllowed}
              className={`group relative w-full flex justify-center py-3 px-4 border border-teal-400/50 text-sm font-medium rounded-md text-white transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-gray-800 focus:ring-teal-500 
                  ${systemConfig.ipCheckEnabled && !isIpAllowed 
                    ? 'bg-gray-600 cursor-not-allowed opacity-50' 
                    : 'bg-teal-700 hover:bg-teal-600 shadow-[0_0_15px_rgba(15,118,110,0.4)]'
                  }`}
            >
              {t('login_btn')}
            </button>
          </div>
        </form>
      </div>

      {/* Footer Credit */}
      <div className="mt-8 text-center text-xs text-gray-500 opacity-60">
          <p>{t('created_by')}</p>
          <p className="mt-1">© 2025</p>
      </div>
    </div>
  );
};

export default LoginScreen;

import React from 'react';
import { createPortal } from 'react-dom';
import { Notification } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';

interface NotificationModalProps {
  notification: Notification;
  onConfirm: () => void;
  resolveName: (username?: string | null) => string;
}

const NotificationModal: React.FC<NotificationModalProps> = ({ notification, onConfirm, resolveName }) => {
  const { t, language } = useLanguage();

  // Rozlíšenie štýlu podľa typu správy (AUDIT vs CHÝBA)
  const isAudit = notification.reason.includes('AUDIT');
  const isMissing = notification.reason.includes('CHÝBA') || notification.reason.includes('MISSING');

  const borderColor = isAudit 
    ? (notification.reason.includes('OK') ? 'border-green-500' : 'border-amber-500')
    : 'border-red-500';

  const iconColor = isAudit 
    ? (notification.reason.includes('OK') ? 'text-green-500' : 'text-amber-500')
    : 'text-red-500';

  const bgColor = isAudit 
    ? (notification.reason.includes('OK') ? 'bg-green-500/10' : 'bg-amber-500/10')
    : 'bg-red-500/10';

  return createPortal(
    <div className="fixed inset-0 z-[11000] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-fade-in">
      <div className={`bg-slate-900 border-2 ${borderColor} rounded-3xl shadow-[0_0_50px_rgba(0,0,0,0.5)] w-full max-w-md overflow-hidden relative flex flex-col`}>

        {/* Header */}
        <div className={`${bgColor} p-6 border-b border-white/5 text-center`}>
            <div className={`w-16 h-16 rounded-2xl bg-slate-900 border-2 ${borderColor} flex items-center justify-center mx-auto mb-4 shadow-lg`}>
                <svg xmlns="http://www.w3.org/2000/svg" className={`h-8 w-8 ${iconColor}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
                </svg>
            </div>
            <h3 className="text-xl font-black text-white uppercase tracking-tighter leading-none">
                {language === 'sk' ? 'DÔLEŽITÁ SPRÁVA' : 'IMPORTANT NOTICE'}
            </h3>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-2">
                {language === 'sk' ? 'Aktualizácia stavu vašej úlohy' : 'Update on your task'}
            </p>
        </div>

        {/* Content */}
        <div className="p-8 space-y-6">
            <div>
                <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Diel / Part Number</p>
                <p className="text-2xl font-mono font-black text-white bg-slate-800 p-3 rounded-xl border border-slate-700 text-center shadow-inner">
                    {notification.partNumber}
                </p>
            </div>

            <div>
                <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Správa / Message</p>
                <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700">
                    <p className={`font-bold text-base ${isMissing ? 'text-red-400' : 'text-white'}`}>
                        {notification.reason}
                    </p>
                </div>
            </div>

            <div className="flex justify-between items-center border-t border-slate-800 pt-4">
                <span className="text-[10px] font-bold text-slate-500 uppercase">
                    {language === 'sk' ? 'Nahlásil:' : 'Reported by:'}
                </span>
                <span className="text-sm font-black text-teal-400 uppercase">
                    {resolveName(notification.reportedBy)}
                </span>
            </div>
        </div>

        {/* Footer Action */}
        <button 
            onClick={onConfirm} 
            className="w-full py-5 bg-slate-800 hover:bg-slate-700 text-white font-black uppercase text-xs tracking-[0.2em] transition-all border-t border-slate-700 hover:text-teal-400"
        >
            {language === 'sk' ? 'BERIEM NA VEDOMIE' : 'ACKNOWLEDGE'}
        </button>
      </div>
    </div>,
    document.body
  );
};

export default NotificationModal;

import React, { useMemo } from 'react';
import PartSearchScreen from './components/PartSearchScreen';
import NotificationModal from './components/modals/NotificationModal';
import { useData } from './context/DataContext';
import { SystemConfig, PriorityLevel, Task } from './types/appTypes';
import { db } from './firebase';
import { collection, addDoc } from 'firebase/firestore';

interface AppAuthenticatedProps {
  currentUser: string;
  currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
  onLogout: () => void;
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
  onUpdateAdminKey: (oldK: string, newK: string) => Promise<void>;
  onToggleAdminLock: (val: boolean) => void;
  installPrompt: any;
  onInstallApp: () => void;
}

const AppAuthenticated: React.FC<AppAuthenticatedProps> = (props) => {
  const data = useData();

  // Získanie notifikácií pre aktuálneho používateľa
  const myNotifications = useMemo(() => {
      if (!data || !data.notifications) return [];
      return data.notifications
        .filter(n => n.targetUser === props.currentUser)
        .sort((a, b) => b.timestamp - a.timestamp); // Najnovšie prvé, ale zobrazujeme ich postupne
  }, [data?.notifications, props.currentUser]);

  // Vyberieme prvú notifikáciu v rade na zobrazenie
  const activeNotification = myNotifications.length > 0 ? myNotifications[0] : null;

  const handleConfirmNotification = () => {
      if (activeNotification && data.onClearNotification) {
          data.onClearNotification(activeNotification.id);
      }
  };

  const resolveName = (username?: string | null) => {
      if (!username) return '-';
      const u = data?.users.find(x => x.username === username);
      return (u?.nickname || username).toUpperCase();
  };

  if (!data || !data.tasks || !data.users) {
      return (
          <div className="w-full h-full flex items-center justify-center bg-gray-900">
              <p className="text-white text-xl font-bold animate-pulse">Načítavam systém...</p>
          </div>
      );
  }

  const partsList = data.partsMap 
    ? Object.entries(data.partsMap).map(([p, d]) => ({ id: p, value: p, description: d }))
    : [];

  const safeGetDocCount = (data as any).onGetDocCount || (async () => 0);
  const safePurgeOldTasks = (data as any).onPurgeOldTasks || (async () => 0);
  const safeExportTasksJSON = (data as any).onExportTasksJSON || (async () => {});
  const safeFetchArchivedTasks = (data as any).onFetchArchivedTasks || (async () => []);
  const safeVerifyAdminPassword = (data as any).onVerifyAdminPassword || ((p: string) => false);
  const safeRequestPart = (data as any).onRequestPart || (async () => false);
  const safeRequestBOM = (data as any).onRequestBOM || (async () => false);
  const safeOnDailyClosing = (data as any).onDailyClosing || (async () => ({ success: false, count: 0 }));
  const safeOnWeeklyClosing = (data as any).onWeeklyClosing || (async () => ({ success: false, count: 0, sanon: '' }));
  const safeFetchSanons = (data as any).fetchSanons || (async () => []);

  const handleCreateInventoryTask = async (partNumber: string, workplace: string | null, quantity: string | null, quantityUnit: string | null, priority: PriorityLevel, isLogistics: boolean = false, noteOrPlate: string = '', isProduction: boolean = false) => {
      if (partNumber === "Počítanie zásob") {
          try {
              await addDoc(collection(db, 'tasks'), {
                  partNumber, workplace: workplace || '', quantity: quantity || '0', quantityUnit: quantityUnit || 'pcs', priority, isLogistics, note: noteOrPlate, text: partNumber, status: 'unpacked', isInProgress: true, inProgressBy: props.currentUser, isDone: false, isMissing: false, createdAt: Date.now(), createdBy: props.currentUser, isProduction: !!isProduction
              });
          } catch (e) { console.error("Failed to create inventory task", e); }
      } else {
          try {
              const newTask: any = {
                  text: partNumber, partNumber, workplace: workplace || '', quantity: quantity || '0', quantityUnit: quantityUnit || 'pcs', priority, isLogistics, isProduction, note: isLogistics ? '' : noteOrPlate, plate: isLogistics ? noteOrPlate : '', isDone: false, isMissing: false, createdAt: Date.now(), createdBy: props.currentUser, status: 'open'
              };
              await addDoc(collection(db, 'tasks'), newTask);
          } catch (e) { console.error("Error adding task", e); }
      }
  };

  const handleUpdateTask = (id: string, updates: any) => { if (data.onUpdateTask) data.onUpdateTask(id, updates); };
  const handleDeleteTask = (id: string) => { if (data.onDeleteTask) data.onDeleteTask(id); };

  const handleToggleTask = async (id: string) => {
      const task = data.tasks.find(t => t.id === id);
      if (!task) return;
      const updates: any = { isDone: !task.isDone };
      if (task.isDone) { updates.completedAt = null; updates.completedBy = null; updates.status = 'open'; updates.isInProgress = false; updates.inProgressBy = null; }
      else { updates.completedAt = Date.now(); updates.completedBy = props.currentUser; updates.status = 'completed'; }
      await data.onUpdateTask(id, updates);
  };

  const handleToggleManualBlock = async (id: string) => {
    const task = data.tasks.find(t => t.id === id);
    if (!task) return;
    const newBlockedState = !task.isManualBlocked;
    const updates: any = { isManualBlocked: newBlockedState };
    if (newBlockedState) { updates.isInProgress = false; updates.inProgressBy = null; updates.priority = 'LOW'; }
    else { updates.createdAt = Date.now(); }
    await data.onUpdateTask(id, updates);
  };

  const handleMarkAsIncorrect = async (id: string) => {
    await data.onUpdateTask(id, { isDone: true, status: 'incorrectly_entered', completedBy: props.currentUser, completedAt: Date.now(), isInProgress: false, inProgressBy: null });
  };

  const handleStartAudit = async (id: string) => {
     await data.onUpdateTask(id, { isAuditInProgress: true, auditBy: props.currentUser, isInProgress: false, inProgressBy: null });
  };

  const handleFinishAudit = async (id: string, result: 'found' | 'missing', note: string) => {
     const task = data.tasks.find(t => t.id === id);
     if (!task) return;
     const badgeText = result === 'found' ? `AUDIT (OK) - ${note}` : `AUDIT (NOK) - ${note}`;
     const updates: any = { isAuditInProgress: false, auditFinalBadge: badgeText, auditBy: null, auditResult: result === 'found' ? 'OK' : 'NOK', auditNote: note, auditedBy: props.currentUser, auditedAt: Date.now() };
     if (result === 'found') { updates.isMissing = false; }
     else { updates.isDone = true; updates.status = 'audit_error'; updates.completedBy = props.currentUser; updates.completedAt = Date.now(); updates.isInProgress = false; }
     await data.onUpdateTask(id, updates);
     if (data.onAddNotification && task.createdBy) {
         await data.onAddNotification({ partNumber: task.partNumber || 'Unknown', reason: `AUDIT: ${result.toUpperCase()} - ${note}`, reportedBy: props.currentUser, targetUser: task.createdBy, timestamp: Date.now() });
     }
  };

  const handleToggleMissing = async (id: string, reason?: string) => {
      await data.onToggleMissing(id, reason);
      if (reason) {
          await data.onUpdateTask(id, { isInProgress: false, inProgressBy: null });
          if (data.onAddNotification) {
              const task = data.tasks.find(t => t.id === id);
              if (task) { await data.onAddNotification({ partNumber: task.partNumber || 'Unknown', reason: `CHÝBA: ${reason}`, reportedBy: props.currentUser, targetUser: task.createdBy || '', timestamp: Date.now() }); }
          }
      }
  };

  return (
    <div className="w-full h-full">
        <PartSearchScreen
          {...(data as any)}
          onAddTask={handleCreateInventoryTask}
          onUpdateTask={handleUpdateTask}
          onDeleteTask={handleDeleteTask}
          onToggleTask={handleToggleTask}
          onToggleManualBlock={handleToggleManualBlock}
          onMarkAsIncorrect={handleMarkAsIncorrect}
          onStartAudit={handleStartAudit}
          onFinishAudit={handleFinishAudit}
          onToggleMissing={handleToggleMissing}
          onDeleteMissingItem={(id) => handleToggleMissing(id)}
          onGetDocCount={safeGetDocCount}
          onPurgeOldTasks={safePurgeOldTasks}
          onExportTasksJSON={safeExportTasksJSON}
          onFetchArchivedTasks={safeFetchArchivedTasks}
          onVerifyAdminPassword={safeVerifyAdminPassword}
          onRequestPart={safeRequestPart}
          onRequestBOM={safeRequestBOM}
          onDailyClosing={safeOnDailyClosing}
          onWeeklyClosing={safeOnWeeklyClosing}
          fetchSanons={safeFetchSanons}
          draftTasks={data.draftTasks || []}
          settings={{ draft: { data: data.draftTasks || [] } }}
          parts={partsList}
          currentUser={props.currentUser}
          currentUserRole={props.currentUserRole}
          onLogout={props.onLogout}
          systemConfig={props.systemConfig}
          onUpdateSystemConfig={props.onUpdateSystemConfig}
          onUpdateAdminKey={props.onUpdateAdminKey}
          onToggleAdminLock={props.onToggleAdminLock}
          installPrompt={props.installPrompt}
          onInstallApp={props.onInstallApp}
          dbLoadWarning={false}
        />

        {activeNotification && (
            <NotificationModal 
                notification={activeNotification}
                onConfirm={handleConfirmNotification}
                resolveName={resolveName}
            />
        )}
    </div>
  );
};

export default AppAuthenticated;

import React from 'react';
import { Task } from '../../../types/appTypes';
import { useLanguage } from '../../LanguageContext';

interface TaskBadgesProps {
  task: Task;
  isSystemInventoryTask: boolean;
  isAuditInProgress: boolean;
  isSearchingMode: boolean;
  isManualBlocked: boolean;
  isUrgent: boolean;
  resolveName: (username?: string | null) => string;
}

const TruckIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16V6a1 1 0 00-1-1H4a1 1 0 00-1 1v10a1 1 0 001 1h1m8-1a1 1 0 01-1 1H9m4-1V8a1 1 0 011-1h2.586a1 1 0 01.707.293l3.414 3.414a1 1 0 01.293.707V16a1 1 0 01-1 1h-1m-6-1a1 1 0 001 1h1M5 17a2 2 0 104 0m-4 0a2 2 0 114 0m6 0a2 2 0 104 0m-4 0a2 2 0 114 0" />
    </svg>
);

const FactoryIcon: React.FC<{ className?: string }> = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-7h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" />
  </svg>
);

const TaskBadges: React.FC<TaskBadgesProps> = ({ 
  task, isSystemInventoryTask, isAuditInProgress, isSearchingMode, isManualBlocked, isUrgent, resolveName
}) => {
  const { t, language } = useLanguage();

  if (task.isDone && task.status !== 'incorrectly_entered') return null;

  const baseBadgeClass = "w-fit px-2.5 py-1 rounded text-[10px] font-black uppercase tracking-widest flex items-center gap-1.5 border shadow-sm backdrop-blur-sm transition-all";

  return (
    <div className="flex flex-wrap gap-2 mb-2.5">
      {task.isProduction && (
        <div className={`${baseBadgeClass} bg-pink-500/10 text-pink-400 border-pink-500/20`}>
          <FactoryIcon className="w-3 h-3" /> {language === 'sk' ? 'VÝROBA' : 'PRODUCTION'}
        </div>
      )}

      {task.isLogistics && (
        <div className={`${baseBadgeClass} bg-indigo-500/10 text-indigo-400 border-indigo-500/20`}>
          <TruckIcon className="w-3 h-3" /> {t('status_logistics')}
        </div>
      )}

      {isSystemInventoryTask && (
        <span className={`${baseBadgeClass} bg-blue-600/20 text-blue-300 border-blue-500/50 animate-pulse shadow-[0_0_10px_rgba(37,99,235,0.2)]`}>
          📋 {t('tab_inventory')} {task.inProgressBy ? `• ${resolveName(task.inProgressBy)}` : ''}
        </span>
      )}

      {!isSystemInventoryTask && task.isInProgress && (
        <span className={`${baseBadgeClass} bg-yellow-500/10 text-yellow-400 border-yellow-500/30 animate-pulse`}>
          👷 {language === 'sk' ? 'RIEŠI' : 'HANDLING'}: {resolveName(task.inProgressBy)}
        </span>
      )}

      {isAuditInProgress && (
        <span className={`${baseBadgeClass} bg-amber-500/10 text-amber-500 border-amber-500/30 animate-pulse`}>
          ⚙️ {language === 'sk' ? 'AUDIT' : 'AUDIT'}: {resolveName(task.auditBy)}
        </span>
      )}

      {isUrgent && !isManualBlocked && (
        <span className={`${baseBadgeClass} bg-orange-500/10 text-orange-500 border-orange-500/40 animate-pulse shadow-[0_0_8px_rgba(249,115,22,0.1)]`}>
          🔥 {t('status_urgent')}
        </span>
      )}

      {isSearchingMode && (
        <span className={`${baseBadgeClass} bg-slate-700/50 text-slate-300 border-slate-600`}>
          🔍 {language === 'sk' ? 'HĽADÁ SA TOVAR' : 'SEARCHING ITEM'}: {resolveName(task.blockedBy)}
        </span>
      )}

      {isManualBlocked && (
        <span className={`${baseBadgeClass} bg-slate-900 text-slate-400 border-slate-700`}>
          🚫 {t('status_blocked')}
        </span>
      )}

      {task.isMissing && task.missingReason && !isAuditInProgress && !isSearchingMode && (
        <span className={`${baseBadgeClass} bg-red-500/10 text-red-500 border-red-500/30 animate-pulse`}>
          ⚠️ {task.missingReason}
        </span>
      )}

      {task.searchedBy && !isSearchingMode && (
        <span className={`${baseBadgeClass} bg-slate-800/60 text-slate-400 border-slate-700`}>
          🕵️ {language === 'sk' ? 'HLADAL' : 'SEARCHED'}: {resolveName(task.searchedBy)}
        </span>
      )}

      {task.status === 'incorrectly_entered' && (
        <div className={`${baseBadgeClass} bg-red-900/10 text-red-400 border-red-800/30 opacity-70`}>
          <svg xmlns="http://www.w3.org/2000/svg" className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M10 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2m7-2a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
          CHYBNE ZADANÉ
        </div>
      )}
    </div>
  );
};

export default TaskBadges;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { useLanguage } from '../LanguageContext';
import PartNumberInput from '../PartNumberInput';
import { Task, PriorityLevel } from '../../types/appTypes';

interface ScannedItem {
    id: string;
    location: string;
    partNumber: string;
    batch: string;
    quantity: string;
    timestamp: number;
    worker: string;
}

interface InventoryTabProps {
    currentUser: string;
    tasks: Task[];
    onAddTask: (pn: string, wp: string | null, qty: string | null, unit: string | null, prio: PriorityLevel, isLogistics?: boolean) => void;
    onUpdateTask: (id: string, updates: Partial<Task>) => void;
    onToggleTask: (id: string) => void;
    onDeleteTask: (id: string) => void;
    hasPermission: (perm: string) => boolean;
    parts: string[];
    onRequestPart: (part: string) => Promise<boolean>;
    resolveName: (username?: string | null) => string;
}

declare var XLSX: any;

const TrashIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
);

const InventoryTab: React.FC<InventoryTabProps> = ({ currentUser, tasks, onAddTask, onUpdateTask, onDeleteTask, parts, onRequestPart, resolveName }) => {
    const { t, language } = useLanguage();

    const locationRef = useRef<HTMLInputElement>(null);
    const partRef = useRef<HTMLInputElement>(null);
    const batchRef = useRef<HTMLInputElement>(null);
    const quantityRef = useRef<HTMLInputElement>(null);

    const [location, setLocation] = useState('');
    const [partNumber, setPartNumber] = useState('');
    const [batch, setBatch] = useState('');
    const [isBatchMissing, setIsBatchMissing] = useState(false);
    const [quantity, setQuantity] = useState('');
    const [lastSaved, setLastSaved] = useState<number | null>(null);
    const [scannedItems, setScannedItems] = useState<ScannedItem[]>([]);

    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        title: string;
        message: React.ReactNode;
        onConfirm: () => void;
        type: 'danger' | 'warning';
    }>({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => {},
        type: 'danger'
    });

    const activeInventoryTask = useMemo(() => {
        return (tasks || []).find(t => 
            t.partNumber === "Počítanie zásob" && 
            !t.isDone && 
            t.inProgressBy === currentUser
        );
    }, [tasks, currentUser]);

    useEffect(() => {
        const saved = localStorage.getItem('inventory_scans');
        if (saved) {
            try {
                const parsed = JSON.parse(saved);
                // OPRAVA: Kontrola, či je parsed pole a nie je null
                if (parsed && Array.isArray(parsed)) {
                    setScannedItems(parsed);
                    if (parsed.length > 0) setLastSaved(parsed[0].timestamp);
                }
            } catch (e) {
                console.error("Failed to parse inventory scans", e);
            }
        }
    }, []);

    useEffect(() => {
        if (scannedItems && scannedItems.length > 0) {
            localStorage.setItem('inventory_scans', JSON.stringify(scannedItems));
            setLastSaved(Date.now());
        }
    }, [scannedItems]);

    const handleStartInventory = () => {
        onAddTask("Počítanie zásob", "Inventúra", "0", "pallet", "NORMAL", true);
    };

    const handleAddItem = () => {
        const isLocEmpty = !location.trim();
        const isPartEmpty = !partNumber.trim();
        const isQtyEmpty = !quantity.trim();
        const isBatchRequiredAndEmpty = !isBatchMissing && !batch.trim();

        if (isLocEmpty || isPartEmpty || isQtyEmpty || isBatchRequiredAndEmpty) {
            const missingFields = [];
            if (isLocEmpty) missingFields.push(language === 'sk' ? "Lokácia" : "Location");
            if (isPartEmpty) missingFields.push(language === 'sk' ? "Diel" : "Part");
            if (isBatchRequiredAndEmpty) missingFields.push("Batch");
            if (isQtyEmpty) missingFields.push(language === 'sk' ? "Množstvo" : "Quantity");

            const errorMsg = language === 'sk' 
                ? `Prosím, vyplňte povinné polia: ${missingFields.join(', ')}.` 
                : `Please fill required fields: ${missingFields.join(', ')}.`;

            alert(errorMsg);
            return;
        }

        const newItem: ScannedItem = {
            id: crypto.randomUUID(),
            location,
            partNumber,
            batch: isBatchMissing ? '[CHÝBA ŠTÍTOK]' : batch,
            quantity,
            timestamp: Date.now(),
            worker: currentUser
        };
        setScannedItems([newItem, ...scannedItems]);

        setLocation(''); 
        setPartNumber(''); 
        setBatch(''); 
        setIsBatchMissing(false);
        setQuantity('');
        setTimeout(() => locationRef.current?.focus(), 10);
    };

    const handleDeleteItem = (id: string) => {
        setConfirmModal({
            isOpen: true,
            title: language === 'sk' ? "Vymazať položku?" : "Delete item?",
            message: language === 'sk' ? "Naozaj chcete vymazať túto naskenovanú položku?" : "Are you sure you want to delete this scanned item?",
            type: 'danger',
            onConfirm: () => {
                const updated = scannedItems.filter(item => item.id !== id);
                setScannedItems(updated);
                if (updated.length === 0) {
                    localStorage.removeItem('inventory_scans');
                }
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
            }
        });
    };

    const handleClearAll = () => {
        setConfirmModal({
            isOpen: true,
            title: language === 'sk' ? "Vymazať všetko?" : "Clear all?",
            message: language === 'sk' ? "Naozaj chcete vymazať celý zoznam naskenovaných položiek? Táto akcia je nevratná." : "Are you sure you want to clear the entire list? This action cannot be undone.",
            type: 'danger',
            onConfirm: () => {
                setScannedItems([]);
                localStorage.removeItem('inventory_scans');
                setLastSaved(null);
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
            }
        });
    };

    const handleCancelInventory = () => {
        setConfirmModal({
            isOpen: true,
            title: language === 'sk' ? "Zrušiť reláciu inventúry?" : "Cancel inventory session?",
            message: (
                <div className="space-y-4">
                    <p className="font-bold text-red-500">
                        {language === 'sk' 
                            ? "Pozor! Táto akcia vymaže všetky naskenované dáta a ukončí inventúru bez uloženia do systému." 
                            : "Warning! This action will delete all scanned data and end the inventory without saving to the system."}
                    </p>
                    <div className="bg-gray-700/50 p-4 rounded-lg border border-gray-600 text-sm">
                        <p className="text-gray-300">
                            {language === 'sk'
                                ? "Ak chcete dáta uložiť a vygenerovať report, použite zelené tlačidlo"
                                : "If you want to save data and generate a report, use the green button"}
                            <span className="text-green-400 font-black ml-1">"EXPORT & UKONČIŤ"</span>.
                        </p>
                    </div>
                </div>
            ),
            type: 'danger',
            onConfirm: () => {
                if (activeInventoryTask) {
                    onDeleteTask(activeInventoryTask.id);
                }
                setScannedItems([]);
                localStorage.removeItem('inventory_scans');
                setLastSaved(null);
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
            }
        });
    };

    const handleExportAndFinish = () => {
        if (!scannedItems || scannedItems.length === 0) {
            alert(language === 'sk' ? "Zoznam je prázdny." : "List is empty.");
            return;
        }

        handleExport();

        const finalCount = scannedItems.length.toString();

        if (activeInventoryTask) {
            onUpdateTask(activeInventoryTask.id, { 
                isDone: true, 
                status: 'completed', 
                completionTime: new Date().toLocaleTimeString('sk-SK'),
                completedBy: currentUser,
                completedAt: Date.now(),
                isInProgress: false,
                inProgressBy: null,
                quantity: finalCount
            });
        }

        setScannedItems([]);
        localStorage.removeItem('inventory_scans');
        setLastSaved(null);
    };

    const handleExport = () => {
        if (!scannedItems || scannedItems.length === 0) return;
        if (typeof XLSX === 'undefined') { alert("Library Error"); return; }
        const data = scannedItems.map(item => ({
            "Dátum inventúry": new Date(item.timestamp).toLocaleDateString('sk-SK'),
            "Užívateľ": resolveName(item.worker),
            "Lokácia": item.location,
            "Číslo dielu": item.partNumber,
            "Batch": item.batch,
            "Množstvo": item.quantity,
            "Presný čas": new Date(item.timestamp).toLocaleTimeString('sk-SK')
        }));
        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Inventúra");
        XLSX.writeFile(wb, `Inventura_${new Date().toISOString().slice(0, 10)}.xlsx`);
    };

    const toggleBatchMissing = () => {
        const newState = !isBatchMissing;
        setIsBatchMissing(newState);
        if (newState) {
            setBatch('[CHÝBA ŠTÍTOK]');
            setTimeout(() => quantityRef.current?.focus(), 10);
        } else {
            setBatch('');
            setTimeout(() => batchRef.current?.focus(), 10);
        }
    };

    const inputBaseClass = "w-full h-12 bg-gray-700 border border-gray-600 rounded-lg px-4 text-white text-base placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-[#4169E1] transition-all font-mono uppercase";
    const dangerButtonClass = "bg-red-900/40 hover:bg-red-800 text-red-100 px-6 py-5 rounded-xl text-base font-black border-2 border-red-800/50 shadow-lg transition-all active:scale-95 uppercase tracking-wider flex items-center justify-center gap-2";

    return (
        <div className="max-w-4xl mx-auto space-y-8 pb-20 animate-fade-in">
            <div className="bg-gray-800 p-6 sm:p-8 rounded-xl shadow-lg border border-gray-700 relative overflow-hidden">
                {!activeInventoryTask ? (
                    <div className="flex flex-col items-center justify-center py-12 space-y-8">
                        <div className="text-center">
                            <h2 className="text-3xl font-bold text-white uppercase tracking-widest">{language === 'sk' ? 'Inventúra nie je spustená' : 'Inventory not started'}</h2>
                            <p className="text-gray-400 text-base mt-3">{language === 'sk' ? 'Kliknutím začnete reláciu počítania.' : 'Click to start a counting session.'}</p>
                        </div>
                        <button 
                            onClick={handleStartInventory}
                            className="bg-[#4169E1] hover:bg-[#3151b1] text-white font-black py-8 px-16 rounded-2xl shadow-[0_0_25px_rgba(65,105,225,0.4)] transition-all active:scale-95 uppercase tracking-[0.25em] text-2xl border-2 border-[#5a81f3]"
                        >
                            📋 {language === 'sk' ? 'Spustiť Inventúru' : 'Start Inventory'}
                        </button>
                    </div>
                ) : (
                    <>
                        <div className="flex justify-between items-start sm:items-center mb-10 border-b border-gray-700 pb-6">
                            <div>
                                <h1 className="text-4xl font-extrabold text-[#4169E1] uppercase tracking-widest leading-none">
                                    {t('tab_inventory')}
                                </h1>
                                <div className="flex gap-6 items-center mt-3">
                                    <span className="bg-[#4169E1]/20 text-[#4169E1] text-xs font-black px-3 py-1 rounded-md border border-[#4169E1]/40 animate-pulse uppercase">Aktívna relácia</span>
                                    <p className="text-xs text-gray-500 uppercase font-mono">
                                        Položiek: <span className="text-white font-bold">{(scannedItems || []).length}</span>
                                    </p>
                                </div>
                            </div>

                            <button 
                                onClick={handleCancelInventory}
                                className={dangerButtonClass.replace('px-6 py-5', 'px-5 py-3 text-xs')}
                            >
                                🛑 {language === 'sk' ? 'Zrušiť reláciu' : 'Cancel session'}
                            </button>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">Skladová Lokácia</label>
                                <input 
                                    ref={locationRef}
                                    type="text"
                                    value={location}
                                    onChange={(e) => setLocation(e.target.value.toUpperCase())}
                                    onKeyDown={(e) => e.key === 'Enter' && partRef.current?.focus()}
                                    placeholder="NAPR. MA123"
                                    className={inputBaseClass}
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">Číslo dielu</label>
                                <PartNumberInput 
                                    inputRef={partRef}
                                    parts={parts}
                                    onPartSelect={(p) => setPartNumber(p || '')}
                                    onInputChange={(val) => setPartNumber(val.toUpperCase())}
                                    onKeyDown={(e) => e.key === 'Enter' && batchRef.current?.focus()}
                                    placeholder={t('part_placeholder')}
                                    value={partNumber}
                                    onRequestPart={onRequestPart}
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">Batch / Číslo várky</label>
                                <div className="flex gap-3">
                                    <input 
                                        ref={batchRef}
                                        type="text"
                                        inputMode="numeric"
                                        readOnly={isBatchMissing}
                                        value={batch}
                                        onChange={(e) => {
                                            if (!isBatchMissing) {
                                                const val = e.target.value.replace(/[^0-9]/g, '').slice(0, 7);
                                                setBatch(val);
                                            }
                                        }}
                                        maxLength={7}
                                        onKeyDown={(e) => e.key === 'Enter' && quantityRef.current?.focus()}
                                        placeholder={isBatchMissing ? '' : "489523"}
                                        className={`${inputBaseClass.replace('w-full', 'w-1/2')} ${isBatchMissing ? 'text-red-500 border-red-900/50 bg-red-900/10' : ''}`}
                                    />
                                    <button 
                                        type="button"
                                        onClick={toggleBatchMissing}
                                        className={`w-1/2 h-12 rounded-lg border-2 font-black uppercase text-xs text-white transition-all flex items-center justify-center gap-2 ${isBatchMissing ? 'bg-red-600 border-red-500 shadow-lg' : 'bg-[#4169E1]/20 border-[#4169E1] hover:bg-[#4169E1]/40'}`}
                                    >
                                        🏷️ {language === 'sk' ? 'Chýba štítok' : 'Label missing'}
                                    </button>
                                </div>
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">Množstvo</label>
                                <input 
                                    ref={quantityRef}
                                    type="text"
                                    inputMode="decimal"
                                    value={quantity}
                                    onChange={(e) => setQuantity(e.target.value.replace(/[^0-9.,]/g, '').slice(0, 7))}
                                    maxLength={7}
                                    onKeyDown={(e) => e.key === 'Enter' && handleAddItem()}
                                    placeholder="0"
                                    className={`${inputBaseClass} font-black text-lg`}
                                />
                            </div>
                        </div>

                        <button 
                            onClick={handleAddItem}
                            className="w-full mt-10 bg-[#4169E1] hover:bg-[#3151b1] text-white font-black py-6 rounded-2xl shadow-xl transition-all active:scale-95 uppercase tracking-widest text-xl border-2 border-[#5a81f3]"
                        >
                            Pridať do zoznamu
                        </button>
                    </>
                )}
            </div>

            {activeInventoryTask && (
                <div className="bg-gray-800 rounded-xl shadow-lg border border-gray-700 overflow-hidden">
                    <div className="p-5 sm:p-8 border-b border-gray-700 bg-gray-900/50 flex flex-col sm:row justify-between items-center gap-8">
                        <div className="flex items-center gap-6">
                            <h3 className="text-gray-400 font-black uppercase text-base tracking-[0.2em] leading-none">
                                {language === 'sk' ? 'SÚPIS POLOŽIEK' : 'ZOZNAM POLOŽIEK'}
                            </h3>
                            <span className="bg-[#4169E1]/20 text-white border-2 border-[#4169E1] text-2xl px-5 py-2 rounded-xl font-black font-mono leading-none shadow-lg">
                                {(scannedItems || []).length}
                            </span>
                        </div>
                        <div className="flex flex-wrap w-full sm:w-auto gap-4">
                            <button 
                                onClick={handleClearAll} 
                                className={dangerButtonClass}
                            >
                                {language === 'sk' ? 'Zmazať všetko' : 'Clear all'}
                            </button>
                            <button 
                                onClick={handleExportAndFinish}
                                className="flex-1 sm:flex-none bg-green-700 hover:bg-green-600 text-white px-10 py-5 rounded-xl text-lg font-black shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 border-2 border-green-500 uppercase tracking-widest"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                                </svg>
                                EXPORT & UKONČIŤ
                            </button>
                        </div>
                    </div>

                    <div className="overflow-x-auto custom-scrollbar">
                        <table className="w-full text-left text-base border-collapse">
                            <thead className="bg-gray-900/30 text-gray-500 text-xs font-black uppercase tracking-widest border-b border-gray-700">
                                <tr>
                                    <th className="py-5 px-6">Čas</th>
                                    <th className="py-5 px-6">Lokácia</th>
                                    <th className="py-5 px-6">Číslo dielu</th>
                                    <th className="py-5 px-6">Batch</th>
                                    <th className="py-5 px-6 text-right">Počet (ks)</th>
                                    <th className="py-5 px-6 text-center"></th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-700/50">
                                {scannedItems && scannedItems.length > 0 ? (
                                    scannedItems.map(item => (
                                        <tr key={item.id} className="text-gray-300 hover:bg-gray-700/30 transition-colors group">
                                            <td className="py-5 px-6 text-xs text-gray-500 font-mono whitespace-nowrap">{new Date(item.timestamp).toLocaleTimeString('sk-SK')}</td>
                                            <td className="py-5 px-6 font-mono font-bold text-[#4169E1] text-lg">{item.location}</td>
                                            <td className="py-5 px-6 font-mono text-white text-base">{item.partNumber}</td>
                                            <td className={`py-5 px-6 font-mono text-base ${item.batch === '[CHÝBA ŠTÍTOK]' ? 'text-red-500 font-bold' : 'text-gray-500'}`}>
                                                {item.batch || '-'}
                                            </td>
                                            <td className="py-5 px-6 font-black text-white text-right font-mono text-xl">{item.quantity}</td>
                                            <td className="py-5 px-6 text-center w-24">
                                                <button 
                                                    onClick={() => handleDeleteItem(item.id)} 
                                                    className="w-16 h-16 flex items-center justify-center rounded-lg bg-red-900/30 text-red-500 hover:bg-red-800 hover:text-white border border-red-800/50 transition-all active:scale-90"
                                                >
                                                    <TrashIcon className="w-8 h-8" />
                                                </button>
                                            </td>
                                        </tr>
                                    ))
                                ) : (
                                    <tr><td colSpan={6} className="py-16 text-center text-gray-600 italic font-bold text-lg">Zoznam je prázdny. Začnite pridávať položky.</td></tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {confirmModal.isOpen && createPortal(
                <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setConfirmModal(prev => ({...prev, isOpen: false}))}>
                    <div className="bg-gray-800 border-2 border-slate-700 rounded-2xl shadow-2xl w-full max-w-md p-8 relative" onClick={e => e.stopPropagation()}>
                        <div className="text-center mb-8">
                            <h3 className={`text-2xl font-black mb-3 uppercase tracking-tighter ${confirmModal.type === 'danger' ? 'text-red-500' : 'text-amber-500'}`}>
                                {confirmModal.title}
                            </h3>
                            <div className="text-gray-300 text-base leading-relaxed">
                                {confirmModal.message}
                            </div>
                        </div>
                        <div className="flex gap-4">
                            <button onClick={() => setConfirmModal(prev => ({...prev, isOpen: false}))} className="flex-1 py-4 bg-gray-700 text-gray-300 rounded-xl hover:bg-gray-600 font-black transition-all uppercase text-xs">
                                {t('btn_cancel')}
                            </button>
                            <button onClick={confirmModal.onConfirm} className={`flex-1 py-4 text-white rounded-xl font-black transition-all shadow-xl uppercase text-xs border-2 ${confirmModal.type === 'danger' ? 'bg-red-600 hover:bg-red-700 border-red-500' : 'bg-amber-600 hover:bg-amber-700 border-amber-500'}`}>
                                POTVRDIŤ
                            </button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default InventoryTab;

import { useMemo } from 'react';
import { Task, SystemBreak, MapSector, DBItem, SystemConfig, PriorityLevel } from '../types/appTypes';

export type FilterMode = 'TODAY' | 'YESTERDAY' | 'WEEK' | 'MONTH' | 'CUSTOM';
export type SourceFilter = 'ALL' | 'PROD' | 'LOG';
export type ShiftFilter = 'ALL' | 'DAY' | 'NIGHT';

export interface AnalyticsFilters {
  mode: FilterMode;
  source: SourceFilter;
  shift: ShiftFilter;
  customStart?: string;
  customEnd?: string;
}

export interface DrivingStats {
    fullDist: number;   // metre
    emptyDist: number;  // metre
    fullRides: number;  // počet jázd s nákladom
    emptyRides: number; // počet jázd naprázdno (vrátane tranzitov)
    efficiency: number; // %
}

export interface WorkerStats {
  id: string;
  name: string;
  index: number; // WPI 0-10
  tasksDone: number;
  pureWorkMinutes: number;
  utilizationPercent: number;
  performanceRatio: number; // Performance (Tempo) %
  avgReactionSeconds: number;
  fullDistMeters: number;
  emptyDistMeters: number;
  logEfficiency: number;
  confidenceRating: number;
  totalRides: number; 
}

export const useAnalyticsEngine = (
  tasks: Task[],
  archivedTasks: Task[],
  systemBreaks: SystemBreak[],
  mapSectors: MapSector[],
  workplaces: DBItem[],
  logisticsOperations: DBItem[],
  systemConfig: SystemConfig,
  filters: AnalyticsFilters,
  resolveName: (username?: string | null) => string
) => {

  const combinedData = useMemo(() => {
    const allTasks = [...tasks, ...archivedTasks];
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const todayTs = today.getTime();

    return allTasks.filter(task => {
      const referenceTime = task.completedAt || task.createdAt || 0;
      if (!referenceTime) return false;

      let timeMatch = false;
      switch (filters.mode) {
        case 'TODAY': timeMatch = referenceTime >= todayTs; break;
        case 'YESTERDAY': timeMatch = referenceTime >= (todayTs - 86400000) && referenceTime < todayTs; break;
        case 'WEEK': timeMatch = referenceTime >= (todayTs - (today.getDay() || 7 - 1) * 86400000); break;
        case 'MONTH': timeMatch = referenceTime >= new Date(today.getFullYear(), today.getMonth(), 1).getTime(); break;
        case 'CUSTOM':
          if (!filters.customStart || !filters.customEnd) return false;
          const startTs = new Date(filters.customStart).getTime();
          const endTs = new Date(filters.customEnd).getTime() + 86399999;
          timeMatch = referenceTime >= startTs && referenceTime <= endTs;
          break;
        default: timeMatch = true;
      }
      if (!timeMatch) return false;

      if (filters.source === 'PROD' && !task.isProduction && task.isLogistics) return false;
      if (filters.source === 'LOG' && !task.isLogistics) return false;

      if (filters.shift !== 'ALL') {
        const hour = new Date(referenceTime).getHours();
        const isDay = hour >= 6 && hour < 18;
        if (filters.shift === 'DAY' && !isDay) return false;
        if (filters.shift === 'NIGHT' && isDay) return false;
      }

      return true;
    });
  }, [tasks, archivedTasks, filters]);

  const engineResult = useMemo(() => {
    const VZV_SPEED_MPS = (systemConfig.vzvSpeed || 8) / 3.6;
    const SHIFT_MINUTES = 450;

    const workerTaskMap: Record<string, Task[]> = {};
    const hourlyLoad: Record<number, { prod: number, log: number }> = {};
    for (let h = 5; h <= 23; h++) { hourlyLoad[h] = { prod: 0, log: 0 }; }

    const workplaceLoad: Record<string, { load: number, pal: number, req: number }> = {};
    const highRunnerLoad: Record<string, { load: number, pal: number, req: number }> = {};
    const missingPartsMap: Record<string, number> = {};

    let globalRealErrors = 0;
    let globalFalseAlarms = 0;
    let globalAuditedCount = 0;

    let globalTotalTargetMin = 0;
    let globalTotalActualMin = 0;

    // --- NEW DETAILED DRIVING STATS INITIALIZATION ---
    const prodDriving: DrivingStats = { fullDist: 0, emptyDist: 0, fullRides: 0, emptyRides: 0, efficiency: 0 };
    const logDriving: DrivingStats = { fullDist: 0, emptyDist: 0, fullRides: 0, emptyRides: 0, efficiency: 0 };

    combinedData.forEach(t => {
      if (t.isDone && t.completedBy) {
        if (!workerTaskMap[t.completedBy]) workerTaskMap[t.completedBy] = [];
        workerTaskMap[t.completedBy].push(t);
      }

      const refTime = t.completedAt || t.createdAt || 0;
      const hour = new Date(refTime).getHours();

      if (hour >= 5 && hour <= 23) {
        const points = (t.quantityUnit === 'pallet' ? parseFloat((t.quantity || '0').replace(',', '.')) : 1) || 1;
        if (t.isLogistics) hourlyLoad[hour].log += points; 
        else hourlyLoad[hour].prod += points;
      }

      if (t.auditResult) {
        globalAuditedCount++;
        if (t.auditResult === 'NOK') globalRealErrors++;
        else globalFalseAlarms++;
      }
      if (t.isMissing && t.partNumber) {
        missingPartsMap[t.partNumber] = (missingPartsMap[t.partNumber] || 0) + 1;
      }
    });

    const calculateBlockedTime = (history: any[] | undefined, startTime: number, endTime: number): number => {
      let totalBlocked = 0;
      systemBreaks.forEach(br => {
        const overlapStart = Math.max(startTime, br.start);
        const overlapEnd = Math.min(endTime, br.end || endTime);
        if (overlapEnd > overlapStart) totalBlocked += (overlapEnd - overlapStart);
      });
      return totalBlocked;
    };

    const workerStatsList: WorkerStats[] = Object.entries(workerTaskMap).map(([uid, workerTasks]) => {
      const sorted = [...workerTasks].sort((a, b) => (a.completedAt || 0) - (b.completedAt || 0));

      let wFullDist = 0;
      let wEmptyDist = 0;
      let wTransitDist = 0;
      let wExecMs = 0;
      let wTargetMinTotal = 0;
      let wActualMinTotal = 0;
      let wReactMs = 0;
      let wReactCount = 0;
      let wMissingReported = 0;
      let wRealErrors = 0;
      let wRides = 0; 
      const daysWorked = new Set<string>();

      let lastCoords: { x: number, y: number } | null = null;

      sorted.forEach(task => {
        if (task.completedAt) daysWorked.add(new Date(task.completedAt).toLocaleDateString());

        const qtyVal = parseFloat((task.quantity || '1').replace(',', '.'));
        const points = (task.quantityUnit === 'pallet') ? qtyVal : 1;

        if (!task.isLogistics) {
            if (task.workplace) {
              if (!workplaceLoad[task.workplace]) workplaceLoad[task.workplace] = { load: 0, pal: 0, req: 0 };
              workplaceLoad[task.workplace].load += points; workplaceLoad[task.workplace].req++;
              if (task.quantityUnit === 'pallet') workplaceLoad[task.workplace].pal += qtyVal;
            }
            if (task.partNumber) {
              if (!highRunnerLoad[task.partNumber]) highRunnerLoad[task.partNumber] = { load: 0, pal: 0, req: 0 };
              highRunnerLoad[task.partNumber].load += points; highRunnerLoad[task.partNumber].req++;
              if (task.quantityUnit === 'pallet') highRunnerLoad[task.partNumber].pal += qtyVal;
            }
        }

        if (task.startedAt && task.completedAt) {
          const rawExecMs = task.completedAt - task.startedAt;
          const blockedMs = calculateBlockedTime(task.inventoryHistory, task.startedAt, task.completedAt);
          let actualMin = (rawExecMs - blockedMs) / 60000;
          const norm = task.isLogistics 
            ? (logisticsOperations.find(o => o.value === task.workplace)?.standardTime || 0)
            : (workplaces.find(w => w.value === task.workplace)?.standardTime || 0);
          const targetMin = norm * qtyVal;

          if (actualMin < 0.5) {
              actualMin = (targetMin * 2) || 2; 
          } else {
              actualMin = Math.max(actualMin, 1);
          }

          wActualMinTotal += actualMin;
          wTargetMinTotal += targetMin;
          wExecMs += Math.max(rawExecMs - blockedMs, 0);
          globalTotalActualMin += actualMin;
          globalTotalTargetMin += targetMin;
        }

        // --- DISTANCE LOGIC WITH SEGMENT SPLIT ---
        let oneWayD = 0;
        if (task.isLogistics) {
          const logOp = logisticsOperations.find(o => o.value === task.workplace);
          if (logOp?.distancePx) {
            oneWayD = logOp.distancePx;
            const durationMs = (task.completedAt || 0) - (task.startedAt || task.createdAt || 0);
            const possibleTrips = Math.round(((durationMs / 1000) * VZV_SPEED_MPS) / (2 * oneWayD));
            const maxQty = Math.max(1, Math.floor(qtyVal));
            const validatedTrips = Math.min(maxQty, Math.max(1, possibleTrips));

            const fullD = validatedTrips * oneWayD;
            const emptyD = (validatedTrips > 1 ? (validatedTrips - 1) * oneWayD : 0);

            wFullDist += fullD;
            wEmptyDist += emptyD;
            wRides += (validatedTrips * 2 - 1); 

            // Accumulate Global Logistics Driving Stats
            logDriving.fullDist += fullD;
            logDriving.emptyDist += emptyD;
            logDriving.fullRides += validatedTrips;
            logDriving.emptyRides += (validatedTrips > 1 ? validatedTrips - 1 : 0);

            lastCoords = null; // Break chain for logistics
          }
        } 
        else if (task.pickedFromSectorId && task.workplace) {
          const sector = mapSectors.find(s => s.id === task.pickedFromSectorId);
          const wp = workplaces.find(w => w.value === task.workplace);
          if (sector && wp) {
            const pickup = { x: sector.coordX, y: sector.coordY };
            const dropoff = { x: wp.coordX || 0, y: wp.coordY || 0 };

            // MANHATTAN DISTANCE (Taxicab Geometry)
            oneWayD = (Math.abs(dropoff.x - pickup.x) + Math.abs(dropoff.y - pickup.y)) / 10;

            let currentTransitD = 0;
            if (lastCoords) {
              // MANHATTAN DISTANCE FOR TRANSIT
              currentTransitD = (Math.abs(pickup.x - lastCoords.x) + Math.abs(pickup.y - lastCoords.y)) / 10;
              wTransitDist += currentTransitD;
              wRides++; 
              // Transit is always an empty ride
              prodDriving.emptyRides += 1;
              prodDriving.emptyDist += currentTransitD;
            } else {
              wRides++;
            }

            const durationMs = (task.completedAt || 0) - (task.startedAt || task.createdAt || 0);
            const possibleTrips = Math.round(((durationMs / 1000) * VZV_SPEED_MPS) / (2 * oneWayD));
            const maxQty = Math.max(1, Math.floor(qtyVal));
            const validatedTrips = Math.min(maxQty, Math.max(1, possibleTrips));

            if (validatedTrips > 0) {
              const fullD = validatedTrips * oneWayD;
              const emptyD = (validatedTrips > 1 ? (validatedTrips - 1) * oneWayD : 0);

              wFullDist += fullD;
              wEmptyDist += emptyD;
              wRides += (validatedTrips * 2 - 1);

              // Accumulate Global Production Driving Stats
              prodDriving.fullDist += fullD;
              prodDriving.emptyDist += emptyD; // This task's internal returns
              prodDriving.fullRides += validatedTrips;
              prodDriving.emptyRides += (validatedTrips > 1 ? validatedTrips - 1 : 0);
            }
            lastCoords = dropoff;
          }
        }

        if (task.createdAt && task.startedAt) {
          const react = task.startedAt - task.createdAt;
          if (react > 0) { wReactMs += react; wReactCount++; }
        }
        if (task.isMissing) {
          wMissingReported++;
          if (task.auditResult === 'NOK') wRealErrors++;
        }
      });

      const nDays = Math.max(daysWorked.size, 1);
      const pureMin = wExecMs / 60000;
      const utilization = (pureMin * 1.15 / (nDays * SHIFT_MINUTES)) * 100;
      const perf = wActualMinTotal > 0 ? Math.min((wTargetMinTotal / wActualMinTotal) * 100, 200) : 0;
      const reactSec = wReactCount > 0 ? (wReactMs / wReactCount) / 1000 : 0;
      const conf = wMissingReported > 0 ? ((wMissingReported - wRealErrors) / wMissingReported) * 100 : 100;
      const totalEmpty = wEmptyDist + wTransitDist;
      const logEff = (wFullDist + totalEmpty) > 0 ? (wFullDist / (wFullDist + totalEmpty)) * 100 : 50;

      const sQual = (conf / 100) * 3.0;
      const sUtil = (Math.min(utilization, 100) / 100) * 2.5;
      const sStd = Math.min(perf, 200) / 200 * 2.0;
      const sReac = reactSec > 0 ? (reactSec < 60 ? 1.0 : reactSec < 180 ? 0.5 : 0) : 0.5;
      const sLog = (logEff / 100) * 1.0;
      const wpi = parseFloat((sQual + sUtil + sStd + sReac + sLog).toFixed(1));

      return {
        id: uid, name: resolveName(uid), index: wpi,
        tasksDone: workerTasks.length, pureWorkMinutes: pureMin,
        utilizationPercent: utilization, performanceRatio: perf,
        avgReactionSeconds: reactSec, fullDistMeters: wFullDist,
        emptyDistMeters: totalEmpty, logEfficiency: logEff, confidenceRating: conf,
        totalRides: wRides
      };
    });

    // --- CALCULATE FINAL EFFICIENCIES ---
    prodDriving.efficiency = (prodDriving.fullDist + prodDriving.emptyDist) > 0 ? (prodDriving.fullDist / (prodDriving.fullDist + prodDriving.emptyDist)) * 100 : 0;
    logDriving.efficiency = (logDriving.fullDist + logDriving.emptyDist) > 0 ? (logDriving.fullDist / (logDriving.fullDist + logDriving.emptyDist)) * 100 : 0;

    const totalFullDistGlobal = prodDriving.fullDist + logDriving.fullDist;
    const totalEmptyDistGlobal = prodDriving.emptyDist + logDriving.emptyDist;
    const totalPhysicalRidesGlobal = workerStatsList.reduce((a, b) => a + b.totalRides, 0);
    const globalPerformanceRatio = globalTotalActualMin > 0 ? Math.min((globalTotalTargetMin / globalTotalActualMin) * 100, 200) : 0;

    return {
      filteredTasks: combinedData,
      globalStats: {
        totalTasks: combinedData.length,
        totalDone: combinedData.filter(t => t.isDone).length,
        totalFullDist: totalFullDistGlobal,
        totalEmptyDist: totalEmptyDistGlobal,
        globalEfficiency: (totalFullDistGlobal + totalEmptyDistGlobal) > 0 ? (totalFullDistGlobal / (totalFullDistGlobal + totalEmptyDistGlobal)) * 100 : 0,
        globalPerformanceRatio: globalPerformanceRatio,
        totalVolume: combinedData.reduce((a, b) => a + (parseFloat((b.quantity || '0').replace(',', '.')) || 0), 0),
        totalPhysicalRides: totalPhysicalRidesGlobal
      },
      drivingStats: {
        production: prodDriving,
        logistics: logDriving
      },
      workerStats: workerStatsList,
      charts: {
        hourly: Object.entries(hourlyLoad).map(([h, d]) => ({ 
          hour: parseInt(h), 
          label: `${h}h`, 
          production: d.prod, 
          logistics: d.log 
        })).sort((a,b) => a.hour - b.hour),
        highRunners: Object.entries(highRunnerLoad).map(([k, v]) => ({ partNumber: k, ...v, totalTasks: v.req, taskRequests: v.req })).sort((a,b) => b.load - a.load).slice(0, 3),
        workplaces: Object.entries(workplaceLoad).map(([k, v]) => ({ workplace: k, ...v, totalTasks: v.req, taskRequests: v.req })).sort((a,b) => b.load - a.load).slice(0, 3)
      },
      qualityStats: {
        realErrorsCount: globalRealErrors,
        falseAlarmsCount: globalFalseAlarms,
        totalAuditedMissing: globalAuditedCount,
        topMissingParts: Object.entries(missingPartsMap).map(([p, c]) => ({ partNumber: p, count: c })).sort((a,b) => b.count - a.count).slice(0, 3)
      }
    };
  }, [combinedData, systemBreaks, mapSectors, workplaces, logisticsOperations, systemConfig, resolveName]);

  return engineResult;
};

import React, { useMemo } from 'react';
import { createPortal } from 'react-dom';
import { Task, SystemBreak, MapSector, DBItem, SystemConfig } from '../../../types/appTypes';
import { useLanguage } from '../../LanguageContext';

interface WorkerDetailModalProps {
  name: string;
  tasks: Task[];
  periodLabel: string;
  systemBreaks: SystemBreak[];
  onClose: () => void;
  mapSectors: MapSector[];
  workplaces: DBItem[];
  systemConfig: SystemConfig;
  logisticsOperations: DBItem[];
}

const WorkerDetailModal: React.FC<WorkerDetailModalProps> = ({ name, tasks, periodLabel, systemBreaks, onClose, mapSectors, workplaces, systemConfig, logisticsOperations }) => {
  const { t, language } = useLanguage();
  const VZV_SPEED_MPS = (systemConfig.vzvSpeed || 8) / 3.6;

  const calculateBlockedTime = (history: any[] | undefined, startTime: number, endTime: number): number => {
    let totalBlocked = 0;
    if (history && history.length > 0) {
      history.forEach(session => {
        const overlapStart = Math.max(startTime, session.start);
        const overlapEnd = Math.min(endTime, session.end || endTime);
        if (overlapEnd > overlapStart) totalBlocked += (overlapEnd - overlapStart);
      });
    }
    systemBreaks.forEach(br => {
      const overlapStart = Math.max(startTime, br.start);
      const overlapEnd = Math.min(endTime, br.end || endTime);
      if (overlapEnd > overlapStart) totalBlocked += (overlapEnd - overlapStart);
    });
    return totalBlocked;
  };

  const stats = useMemo(() => {
    let totalLoad = 0;
    let palCount = 0;
    let pcsTasks = 0;
    let missingReported = 0;
    let realErrors = 0;
    let totalExecMs = 0; // Reálne odpracovaný čas (nezmenený)
    let totalStandardMin = 0;
    let totalReactionMs = 0;
    let reactionCount = 0;
    let durations: number[] = [];

    // Nové akumulátory pre férový výkon s limitom (Capped Average)
    let sumPerformance = 0;
    let countPerformanceTasks = 0;

    let totalFullDist = 0;
    let totalEmptyDist = 0;
    let totalTransitBetweenTasksDist = 0;

    const workplacesMap: Record<string, number> = {};
    const partsMap: Record<string, number> = {};
    const uniqueDaysWorked = new Set<string>();

    const sortedTasks = [...tasks].sort((a,b) => (a.completedAt || 0) - (b.completedAt || 0));
    let lastWorkplaceCoords: { x: number, y: number } | null = null;

    sortedTasks.forEach(task => {
      if (task.completedAt) {
        const dateKey = new Date(task.completedAt).toLocaleDateString('sk-SK');
        uniqueDaysWorked.add(dateKey);
      }

      const qtyVal = parseFloat((task.quantity || '1').replace(',', '.'));
      const loadPoints = (task.quantityUnit === 'pallet' && !isNaN(qtyVal)) ? qtyVal : 1;
      totalLoad += loadPoints;

      if (task.quantityUnit === 'pallet') palCount += qtyVal;
      else pcsTasks++;

      if (task.isDone && task.completedBy) {
          let validatedTrips = 0;
          let oneWayD = 0;

          // 1. CHAINING LOGIC
          if (lastWorkplaceCoords && !task.isLogistics && task.pickedFromSectorId) {
              const sector = mapSectors.find(s => s.id === task.pickedFromSectorId);
              if (sector) {
                  // MANHATTAN DISTANCE (Transit)
                  const transitD = (Math.abs(sector.coordX - lastWorkplaceCoords.x) + Math.abs(sector.coordY - lastWorkplaceCoords.y)) / 10;
                  totalTransitBetweenTasksDist += transitD;
              }
          }

          // 2. TASK DISTANCE
          if (task.isLogistics) {
              const logOp = logisticsOperations.find(o => o.value === task.workplace);
              if (logOp && logOp.distancePx) {
                  oneWayD = logOp.distancePx;
                  const durationMs = (task.completedAt || 0) - (task.startedAt || task.createdAt || 0);
                  const possibleTrips = Math.round(( (durationMs / 1000) * VZV_SPEED_MPS ) / (2 * oneWayD));
                  validatedTrips = Math.min(Math.max(1, Math.floor(qtyVal)), Math.max(1, possibleTrips));
              }
          } else if (task.pickedFromSectorId && task.workplace) {
              const sector = mapSectors.find(s => s.id === task.pickedFromSectorId);
              const wp = workplaces.find(w => w.value === task.workplace);
              if (sector && wp) {
                  const dx = (wp.coordX || 0) - (sector.coordX || 0);
                  const dy = (wp.coordY || 0) - (sector.coordY || 0);
                  // MANHATTAN DISTANCE (Task)
                  oneWayD = (Math.abs(dx) + Math.abs(dy)) / 10;
                  const durationMs = (task.completedAt || 0) - (task.startedAt || task.createdAt || 0);
                  const possibleTrips = Math.round(( (durationMs / 1000) * VZV_SPEED_MPS ) / (2 * oneWayD));
                  validatedTrips = Math.min(Math.max(1, Math.floor(qtyVal)), Math.max(1, possibleTrips));
                  lastWorkplaceCoords = { x: wp.coordX || 0, y: wp.coordY || 0 };
              }
          }

          if (validatedTrips > 0) {
              totalFullDist += validatedTrips * oneWayD;
              totalEmptyDist += (validatedTrips > 1 ? (validatedTrips - 1) * oneWayD : 0);
          }
      }

      // --- HLAVNÝ VÝPOČET ČASU A VÝKONU (CAP + ANTI-CHEAT) ---
      if (task.startedAt && task.completedAt) {
        const rawDurationMs = task.completedAt - task.startedAt;
        const blockedMs = calculateBlockedTime(task.inventoryHistory, task.startedAt, task.completedAt);
        const realDurationMs = Math.max(rawDurationMs - blockedMs, 0);

        // 1. Reálny čas práce pre displej dochádzky
        totalExecMs += realDurationMs;
        durations.push(realDurationMs);

        // 2. Vyhľadanie normy
        const norm = task.isLogistics 
            ? (logisticsOperations.find(o => o.value === task.workplace)?.standardTime || 0)
            : (workplaces.find(w => w.value === task.workplace)?.standardTime || 0);

        const targetMin = norm * qtyVal;
        const durationMin = realDurationMs / 60000;

        // 3. Adjusted Time Logic (Anti-Cheat & Floor)
        let adjustedMin;
        if (durationMin < 0.5) {
            // PENALTY: Úloha pod 30s -> berie sa ako 2x norma (Vždy 50%)
            adjustedMin = (targetMin * 2) || 2; 
        } else if (durationMin < 1) {
            // Safety Floor (Min 1 minúta)
            adjustedMin = 1;
        } else {
            // Reálny čistý čas
            adjustedMin = durationMin;
        }

        // 4. Per-task Performance s limitom 200%
        if (targetMin > 0) {
            const taskPerf = (targetMin / adjustedMin) * 100;
            const cappedPerf = Math.min(taskPerf, 200);
            sumPerformance += cappedPerf;
            countPerformanceTasks++;
            totalStandardMin += targetMin;
        }
      }

      if (task.createdAt && task.startedAt) {
        const react = task.startedAt - task.createdAt;
        if (react > 0) { totalReactionMs += react; reactionCount++; }
      }

      const isProd = (task.isProduction === true) || (!task.isLogistics && !!task.workplace);
      if (isProd && task.workplace) workplacesMap[task.workplace] = (workplacesMap[task.workplace] || 0) + 1;
      if (task.partNumber) partsMap[task.partNumber] = (partsMap[task.partNumber] || 0) + 1;

      if (task.isMissing) {
        missingReported++;
        if (task.auditResult === 'NOK') realErrors++;
      }
    });

    const numDays = Math.max(uniqueDaysWorked.size, 1);
    const SHIFT_MINUTES = 450;
    const totalAvailableMinutes = numDays * SHIFT_MINUTES;
    const pureWorkMinutes = totalExecMs / 60000;

    // WPI Score Logic
    const performanceRatio = countPerformanceTasks > 0 ? (sumPerformance / countPerformanceTasks) : 0;
    const avgReactionSeconds = reactionCount > 0 ? (totalReactionMs / reactionCount) / 1000 : 0;
    const confidenceRating = missingReported > 0 ? ((missingReported - realErrors) / missingReported) * 100 : 100;
    const grandTotalEmptyDist = totalEmptyDist + totalTransitBetweenTasksDist;
    const logEfficiency = (totalFullDist + grandTotalEmptyDist) > 0 ? (totalFullDist / (totalFullDist + grandTotalEmptyDist)) * 100 : 50;

    const utilizationPercent = (pureWorkMinutes * 1.15 / totalAvailableMinutes) * 100;

    const scoreQuality = (confidenceRating / 100) * 3.0;
    const scoreUtilization = (Math.min(utilizationPercent, 100) / 100) * 2.5;
    const scoreStandards = performanceRatio > 0 ? (Math.min(performanceRatio, 200) / 200) * 2.0 : 1.0; 
    const scoreReaction = avgReactionSeconds > 0 ? (avgReactionSeconds < 60 ? 1.0 : avgReactionSeconds < 180 ? 0.5 : 0) : 0.5;
    const scoreLogistics = (logEfficiency / 100) * 1.0;

    const workerIndex = parseFloat((scoreQuality + scoreUtilization + scoreStandards + scoreReaction + scoreLogistics).toFixed(1));

    return {
      totalLoad, palCount, pcsTasks, 
      confidenceRating, realErrors, missingReported,
      totalExecMs, 
      avgMsPerPoint: durations.length > 0 ? totalExecMs / totalLoad : 0,
      topWorkplaces: Object.entries(workplacesMap).sort(([,a],[,b]) => b-a).slice(0, 3).map(([name, count]) => ({ name, count })),
      topParts: Object.entries(partsMap).sort(([,a],[,b]) => b-a).slice(0, 3).map(([name, count]) => ({ name, count })),
      utilizationPercent, pureWorkMinutes, workerIndex, performanceRatio, avgReactionSeconds,
      totalFullDist, totalEmptyDist: grandTotalEmptyDist, transitOnlyDist: totalTransitBetweenTasksDist,
      logEfficiency, totalStandardMin
    };
  }, [tasks, systemBreaks, mapSectors, workplaces, systemConfig, VZV_SPEED_MPS, logisticsOperations]);

  const formatDuration = (ms: number) => {
    if (ms <= 0) return '-';
    const minutes = Math.round(ms / 60000);
    if (minutes < 1) return '< 1 min';
    if (minutes >= 60) return `${Math.floor(minutes / 60)}h ${minutes % 60}m`;
    return `${minutes} min`;
  };

  const formatMinutes = (totalMin: number) => {
    const h = Math.floor(totalMin / 60);
    const m = Math.round(totalMin % 60);
    return h > 0 ? `${h}h ${m}m` : `${m} min`;
  };

  return createPortal(
    <div className="fixed inset-0 z-[10000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in" onClick={onClose}>
      <div className="bg-slate-900 border-2 border-slate-800 rounded-[2.5rem] shadow-[0_0_100px_rgba(0,0,0,0.8)] w-full max-w-6xl p-8 relative overflow-hidden flex flex-col max-h-[95vh]" onClick={e => e.stopPropagation()}>

        {/* Background Decor */}
        <div className="absolute top-0 right-0 w-96 h-96 bg-teal-500/5 rounded-full -mr-48 -mt-48 blur-[100px]"></div>
        <div className="absolute bottom-0 left-0 w-96 h-96 bg-purple-500/5 rounded-full -ml-48 -mb-48 blur-[100px]"></div>

        {/* Header */}
        <div className="flex justify-between items-start mb-10 relative z-10 border-b border-white/5 pb-8">
          <div>
            <div className="flex items-center gap-4 mb-2">
