               <div className="space-y-6">
                  <div>
                     <label className={labelClass}>NÁZOV OPERÁCIE</label>
                     <input 
                        value={editingLog.value} 
                        onChange={e => setEditingLog({...editingLog, value: e.target.value.toUpperCase()})}
                        className={inputClass}
                        placeholder="NAPR. VYKLÁDKA"
                        autoFocus
                     />
                  </div>

                  <div>
                     <label className={`${labelClass} text-indigo-400`}>VZDIALENOSŤ TRASY (PX)</label>
                     <input 
                        type="number" 
                        value={editingLog.distancePx} 
                        onChange={e => setEditingLog({...editingLog, distancePx: parseInt(e.target.value)})}
                        className={`${inputClass} border-indigo-500/30 focus:border-indigo-500 text-indigo-400`}
                     />
                     <p className="text-[9px] text-slate-500 mt-1 uppercase font-bold">* Pri rýchlosti {props.systemConfig.vzvSpeed} km/h to ovplyvní travel time.</p>
                  </div>

                  <div className="grid grid-cols-2 gap-6">
                     <div>
                        <label className={`${labelClass} text-amber-500`}>SETUP TIME</label>
                        <input 
                           type="number" 
                           value={editingLog.setupTime} 
                           onChange={e => setEditingLog({...editingLog, setupTime: parseFloat(e.target.value)})}
                           className={`${inputClass} border-amber-500/30 text-amber-400`}
                        />
                     </div>
                     <div>
                        <label className={`${labelClass} text-teal-500`}>UNIT TIME</label>
                        <input 
                           type="number" 
                           value={editingLog.unitTime} 
                           onChange={e => setEditingLog({...editingLog, unitTime: parseFloat(e.target.value)})}
                           className={`${inputClass} border-teal-500/30 text-teal-400`}
                        />
                     </div>
                  </div>

                  <div className="flex gap-3 mt-8">
                     <button onClick={() => setIsLogModalOpen(false)} className="flex-1 h-14 rounded-xl font-black uppercase tracking-widest text-slate-400 hover:bg-slate-800 transition-colors">
                        Zrušiť
                     </button>
                     <button onClick={handleSaveLog} className="flex-1 h-14 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl font-black uppercase tracking-widest shadow-lg transition-all active:scale-95">
                        Uložiť
                     </button>
                  </div>
               </div>
            </div>
         </div>,
         document.body
      )}

    </div>
  );
});

export default WorkplaceSection;

import React, { useState, useMemo, memo } from 'react';
